import React, { useState, useEffect } from 'react';
import { auth, db } from './Firebase';
import { collection, addDoc, getDocs, updateDoc, deleteDoc, doc } from 'firebase/firestore';
import { getStorage, ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import './AdminDashboard.css';

const AdminDashboard = () => {
  const [activeTab, setActiveTab] = useState('courses');
  const [courses, setCourses] = useState([]);
  const [events, setEvents] = useState([]);
  const [newCourse, setNewCourse] = useState({
    title: '',
    description: '',
    level: 'Beginner',
    duration: '',
    image: null
  });
  const [newEvent, setNewEvent] = useState({
    title: '',
    description: '',
    date: '',
    location: '',
    image: null
  });

  useEffect(() => {
    fetchCourses();
    fetchEvents();
  }, []);

  const fetchCourses = async () => {
    try {
      const coursesCollection = collection(db, 'courses');
      const coursesSnapshot = await getDocs(coursesCollection);
      const coursesList = coursesSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      setCourses(coursesList);
    } catch (error) {
      console.error('Error fetching courses:', error);
    }
  };

  const fetchEvents = async () => {
    try {
      const eventsCollection = collection(db, 'events');
      const eventsSnapshot = await getDocs(eventsCollection);
      const eventsList = eventsSnapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      }));
      setEvents(eventsList);
    } catch (error) {
      console.error('Error fetching events:', error);
    }
  };

  const handleImageUpload = async (file, type) => {
    if (!file) return null;
    const storage = getStorage();
    const storageRef = ref(storage, `${type}/${file.name}`);
    await uploadBytes(storageRef, file);
    return await getDownloadURL(storageRef);
  };

  const handleCourseSubmit = async (e) => {
    e.preventDefault();
    try {
      const imageUrl = await handleImageUpload(newCourse.image, 'courses');
      const courseData = {
        ...newCourse,
        imageUrl,
        createdAt: new Date().toISOString()
      };
      await addDoc(collection(db, 'courses'), courseData);
      setNewCourse({
        title: '',
        description: '',
        level: 'Beginner',
        duration: '',
        image: null
      });
      fetchCourses();
    } catch (error) {
      console.error('Error adding course:', error);
    }
  };

  const handleEventSubmit = async (e) => {
    e.preventDefault();
    try {
      const imageUrl = await handleImageUpload(newEvent.image, 'events');
      const eventData = {
        ...newEvent,
        imageUrl,
        createdAt: new Date().toISOString()
      };
      await addDoc(collection(db, 'events'), eventData);
      setNewEvent({
        title: '',
        description: '',
        date: '',
        location: '',
        image: null
      });
      fetchEvents();
    } catch (error) {
      console.error('Error adding event:', error);
    }
  };

  const handleDelete = async (id, type) => {
    try {
      await deleteDoc(doc(db, type, id));
      if (type === 'courses') {
        fetchCourses();
      } else {
        fetchEvents();
      }
    } catch (error) {
      console.error(`Error deleting ${type}:`, error);
    }
  };

  return (
    <div className="admin-dashboard">
      <h1>Admin Dashboard</h1>
      
      <div className="tab-buttons">
        <button 
          className={activeTab === 'courses' ? 'active' : ''} 
          onClick={() => setActiveTab('courses')}
        >
          Manage Courses
        </button>
        <button 
          className={activeTab === 'events' ? 'active' : ''} 
          onClick={() => setActiveTab('events')}
        >
          Manage Events
        </button>
      </div>

      {activeTab === 'courses' && (
        <div className="courses-section">
          <h2>Add New Course</h2>
          <form onSubmit={handleCourseSubmit}>
            <input
              type="text"
              placeholder="Course Title"
              value={newCourse.title}
              onChange={(e) => setNewCourse({...newCourse, title: e.target.value})}
              required
            />
            <textarea
              placeholder="Course Description"
              value={newCourse.description}
              onChange={(e) => setNewCourse({...newCourse, description: e.target.value})}
              required
            />
            <select
              value={newCourse.level}
              onChange={(e) => setNewCourse({...newCourse, level: e.target.value})}
            >
              <option value="Beginner">Beginner</option>
              <option value="Intermediate">Intermediate</option>
              <option value="Advanced">Advanced</option>
            </select>
            <input
              type="text"
              placeholder="Duration (e.g., 6 weeks)"
              value={newCourse.duration}
              onChange={(e) => setNewCourse({...newCourse, duration: e.target.value})}
              required
            />
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setNewCourse({...newCourse, image: e.target.files[0]})}
              required
            />
            <button type="submit">Add Course</button>
          </form>

          <h2>Existing Courses</h2>
          <div className="courses-list">
            {courses.map(course => (
              <div key={course.id} className="course-item">
                <img src={course.imageUrl} alt={course.title} />
                <h3>{course.title}</h3>
                <p>{course.description}</p>
                <p>Level: {course.level}</p>
                <p>Duration: {course.duration}</p>
                <button onClick={() => handleDelete(course.id, 'courses')}>Delete</button>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeTab === 'events' && (
        <div className="events-section">
          <h2>Add New Event</h2>
          <form onSubmit={handleEventSubmit}>
            <input
              type="text"
              placeholder="Event Title"
              value={newEvent.title}
              onChange={(e) => setNewEvent({...newEvent, title: e.target.value})}
              required
            />
            <textarea
              placeholder="Event Description"
              value={newEvent.description}
              onChange={(e) => setNewEvent({...newEvent, description: e.target.value})}
              required
            />
            <input
              type="datetime-local"
              value={newEvent.date}
              onChange={(e) => setNewEvent({...newEvent, date: e.target.value})}
              required
            />
            <input
              type="text"
              placeholder="Location"
              value={newEvent.location}
              onChange={(e) => setNewEvent({...newEvent, location: e.target.value})}
              required
            />
            <input
              type="file"
              accept="image/*"
              onChange={(e) => setNewEvent({...newEvent, image: e.target.files[0]})}
              required
            />
            <button type="submit">Add Event</button>
          </form>

          <h2>Existing Events</h2>
          <div className="events-list">
            {events.map(event => (
              <div key={event.id} className="event-item">
                <img src={event.imageUrl} alt={event.title} />
                <h3>{event.title}</h3>
                <p>{event.description}</p>
                <p>Date: {new Date(event.date).toLocaleString()}</p>
                <p>Location: {event.location}</p>
                <button onClick={() => handleDelete(event.id, 'events')}>Delete</button>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
